import json

def build_entry(span, citation_type, is_valid, aya_ref=None, hadith_ref=None, corrected_text=None, completely_invalid=False):
    return {
        "span_start": span["span_start"],
        "span_end": span["span_end"],
        "span_text": span["span_text"],
        "citation_type": citation_type,
        "is_valid": is_valid,
        "aya_reference": aya_ref or {},
        "hadeeth_reference": hadith_ref or {},
        "corrected_text": corrected_text if corrected_text is not None else span["span_text"],
        "completely_invalid": completely_invalid
    }

results = []

for s in spans:
    t = s["span_text"]
    if t.strip() == "إِنَّا هَدَيْنَاهُ السَّبِيلَ إِمَّا شَاكِرًا وَإِمَّا كَفُورًا":
        results.append(build_entry(
            s, "Aya", True,
            aya_ref={"sura_name": "الإنسان", "sura_number": 76, "aya_number": 3},
            corrected_text=t
        ))
    elif t.strip() == "فَمَنْ شَاءَ اتَّخَذَ إِلَىٰ رَبِّهِ سَبِيلًا":
        # choose one canonical verse where this exact phrase appears fully: 76:29 and 73:19 both contain it
        results.append(build_entry(
            s, "Aya", True,
            aya_ref={"sura_name": "الإنسان", "sura_number": 76, "aya_number": 29},
            corrected_text=t
        ))
    elif t.strip().startswith("إنما الأعمال بالنيات"):
        results.append(build_entry(
            s, "Hadeeth", True,
            hadith_ref={"collection_name": "Sahih al-Bukhari", "book_number": 1, "hadith_number": 1},
            corrected_text=t
        ))
    elif t.strip().startswith("لا يؤمن أحدكم حتى يكون هواه تبعًا لما جئت به"):
        results.append(build_entry(
            s, "Hadeeth", True,
            hadith_ref={"collection_name": "An-Nawawi's Forty Hadith", "book_number": 1, "hadith_number": 41},
            corrected_text=t
        ))
    else:
        # Fallback (shouldn't happen here)
        results.append(build_entry(
            s, "Hadeeth", False,
            corrected_text="خطأ",
            completely_invalid=True
        ))

output = {"citations": results}
print(json.dumps(output, ensure_ascii=False, indent=2))
